import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const g=JSON.parse('{"title":"SOP-006: Release & Deployment","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-006-release-deploy.md","filePath":"sops/SOP-006-release-deploy.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-006-release-deploy.md"};function n(l,e,s,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="sop-006-release-deployment" tabindex="-1">SOP-006: Release &amp; Deployment <a class="header-anchor" href="#sop-006-release-deployment" aria-label="Permalink to &quot;SOP-006: Release &amp; Deployment&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> SRE · <strong>Gate:</strong> G3</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Progressive deployment to AWS with automated verification at each stage. Tier determines approval requirements.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>SRE</td><td><strong>A</strong> — prod safety</td></tr><tr><td>DEV</td><td>R — fix deploy failures</td></tr><tr><td>PO</td><td><strong>A</strong> — staging behavior sign-off (T1/T2 user-facing)</td></tr><tr><td>ARCH</td><td>C — T1 deploy approval</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Merge to <code>main</code> or release branch</li><li>Container in ECR with scan pass (no Critical CVEs)</li><li>Feature flags configured in AppConfig if gradual rollout</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><h3 id="staging" tabindex="-1">Staging <a class="header-anchor" href="#staging" aria-label="Permalink to &quot;Staging&quot;">​</a></h3><ol><li><strong>Pipeline trigger</strong> — CodePipeline / GitHub Actions deploys to staging account.</li><li><strong>Automated verification</strong> — Contract + integration + E2E against staging; DAST if configured.</li><li><strong>Synthetic smoke</strong> — CloudWatch Synthetics canaries pass.</li><li><strong>PO staging sign-off</strong> — PO confirms acceptance criteria on staging (not manual QA scripts — demo + green metrics). Record in ticket.</li></ol><h3 id="production" tabindex="-1">Production <a class="header-anchor" href="#production" aria-label="Permalink to &quot;Production&quot;">​</a></h3><ol start="5"><li><strong>Pre-deploy</strong> — Verify SLO error budget not exhausted; freeze if burn rate critical.</li><li><strong>Deploy strategy</strong> — T1: blue/green or canary 10% → 50% → 100%. T2: automated canary. T3: rolling.</li><li><strong>T1 approval</strong> — SRE + ARCH manual approve in pipeline gate before prod promotion.</li><li><strong>Metric gate</strong> — Compare error rate, p99 latency vs pre-deploy baseline (15 min window). Auto-rollback on breach.</li><li><strong>Post-deploy</strong> — Enable/update monitoring baselines; verify canaries green 30 min.</li><li><strong>Close loop</strong> — Update ticket; notify stakeholders.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Staging synthetics green</li><li>[ ] PO sign-off recorded (T1/T2 user-facing)</li><li>[ ] Prod deploy complete with metric gate passed</li><li>[ ] Canaries green 30 min post-deploy</li><li>[ ] Deploy recorded in change log / Backstage</li></ul><h2 id="sla-escalation" tabindex="-1">SLA &amp; escalation <a class="header-anchor" href="#sla-escalation" aria-label="Permalink to &quot;SLA &amp; escalation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Max deploy window</th><th>Rollback trigger</th></tr></thead><tbody><tr><td>T1</td><td>Business hours preferred</td><td>Auto on SLO breach</td></tr><tr><td>T2</td><td>Anytime with canary</td><td>Auto on canary fail</td></tr><tr><td>T3</td><td>Anytime</td><td>Auto on health check fail</td></tr></tbody></table><p>Escalation: failed rollback → Sev-1 <a href="./SOP-007-incident-response.html">SOP-007</a>.</p><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-005-pr-review.html">SOP-005</a> · <a href="./SOP-007-incident-response.html">SOP-007</a> · <a href="./../cicd-observability.html">cicd-observability.md</a></li></ul>',20)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
